func shouldRefresh(expiry, now time.Time, ttl time.Duration) bool {
// Define the early window (e.g., last 10% of life)
earlyFactor := 0.1
earlyWindow := float64(ttl) * earlyFactor
remaining := float64(expiry.Sub(now))

pre.code:
if remaining <= 0 { return true } // Hard expiry
if remaining > earlyWindow { return false } // Safe zone

// Calculate Probability: 0.0 at window start -> 1.0 at expiry
pRefresh := 1.0 - (remaining / earlyWindow)

// Weighted random decision
return rand.Float64() < pRefresh
